var async = require('async'), config, knox = require('knox'),

store = function(path, srcDstNames, bucket, callback) {
  
  if (typeof bucket == 'function') {
    callback = bucket;
    bucket = config.bucket;
  };

  var client = knox.createClient({ key: config.key, secret: config.secret, bucket: bucket});

  async.each(srcDstNames, function(item, callback) {

    client.putFile(path + '/' + item.src, item.dst, config.fileOptions, function(err, res) {

      if (err) 
        callback(err);
      else
        callback();

    });


  }, callback);

},

remove = function(name, bucket, callback) {

  if (typeof bucket == 'function') {
    callback = bucket;
    bucket = config.bucket;
  };

  var client = knox.createClient({ key: config.key, secret: config.secret, bucket: bucket});

  client.deleteFile(name, callback);

};


module.exports = function(initConfig) {

  config = initConfig; //key, secret, default bucket

  config.fileOptions = { 'x-amz-acl': 'public-read', 'Content-Type': 'image/jpg' };

  return {
    store: store,
    remove: remove
  }

};